rning\"},{\"color\":\"#f5a524\",\"slug\":\"palette15\",\"name\":\"Palette Color Rating\"}],\"active\":\"palette\"}','on'),(254,'kadence_starter_plugin_notice','1','off'),(262,'kadence_uplink_auth_token','99729719-913f-4c28-b940-32a687b464d6','auto'),(263,'stellarwp_uplink_license_key_kadence-blocks','f5be0fccccd3cafa0a6d65041036cc2462f66164','auto'),(264,'stellarwp_uplink_license_key_status_kadence-blocks_danil.local','valid','auto'),(265,'stellarwp_uplink_license_key_status_kadence-blocks_danil.local_timeout','43200','auto'),(270,'kadence_starter_templates_config','{\"starterType\":\"ai\",\"aiStatus\":\"\"}','auto'),(271,'kadence_blocks_prophecy','{\"firstTime\":false,\"isSubmitted\":true,\"context\":\"kadence\",\"companyName\":\"danil\",\"entityType\":\"INDIVIDUAL\",\"locationType\":\"Online Only\",\"locationInput\":\"\",\"location\":\"Online Only\",\"industry\":\"Church Choir\",\"missionStatement\":\"Александро-Невский военный собор — выдающаяся церковь Екатеринодарской епархии Русской Православной Церкви, расположенная в Краснодаре. Построенный в период с 1853 по 1872 год, этот исторический собор служил важной духовной и культурной достопримечательностью. Однако его постигла трагическая участь: в 1932 году, в период государственного противодействия религиозным учреждениям, он был снесён.\\n\\nПосле масштабной реставрации собор был тщательно восстановлен в период с 2003 по 2006 год, что продемонстрировало стойкость местного сообщества и его стремление сохранить религиозное наследие. Сегодня Александро-Невский собор является не только местом поклонения, но и символом исторической преемственности и культурной гордости для жителей Краснодара. Его впечатляющая архитектура и историческое значение делают его выдающимся местом в регионе, привлекающим как туристов, так и верующих, стремящихся прикоснуться к его богатому прошлому.\",\"keywords\":[\"церковь\",\"собор\",\"казачество\",\"войсковой\",\"Александро-Невский\",\"молитва\",\"духовенство\"],\"tone\":\"NEUTRAL\",\"privacyAgreement\":false,\"photoLibrary\":\"aiGenerated\",\"featuredImages\":[],\"backgroundImages\":[],\"customCollections\":[{\"label\":\"My Images\",\"value\":\"my-images\",\"galleries\":[{\"name\":\"featured\",\"isLocal\":true,\"images\":[]},{\"name\":\"background\",\"isLocal\":true,\"images\":[]}]}],\"verticals\":[],\"suggestedKeywords\":[\"Religious Heritage\",\"Cultural Significance\",\"Historical Architecture\",\"Community Resilience\",\"Restoration Projects\",\"Orthodox Christianity\",\"Spiritual Landmark\",\"Tourist Attraction\",\"Cultural Pride\",\"Church Choir\"],\"suggestedKeywordsState\":\"success\",\"imageSearchQuery\":\"church choir images choir members singing religious music worship service choir performance church architecture stained glass windows spiritual community worship gathering religious events choir robes choir director\",\"lang\":\"\",\"goals\":[\"donations\"]}','auto'),(297,'theme_mods_church-kadence-child','a:31:{i:0;b:0;s:18:\"nav_menu_locations\";a:1:{s:7:\"primary\";i:4;}s:18:\"custom_css_post_id\";i:26;s:16:\"sidebars_widgets\";a:2:{s:4:\"time\";i:1772961577;s:4:\"data\";a:2:{s:19:\"wp_inactive_widgets\";a:5:{i:0;s:7:\"block-2\";i:1;s:7:\"block-3\";i:2;s:7:\"block-4\";i:3;s:7:\"block-5\";i:4;s:7:\"block-6\";}s:8:\"footer-1\";a:0:{}}}s:15:\"initial_version\";s:5:\"1.4.5\";s:17:\"church_main_image\";s:71:\"http://danil.local/wp-content/uploads/2026/03/ukY7RJWKF6iBluOGj2Jg.webp\";s:18:\"church_description\";s:1431:\"Войсковой собор Александра Невского в Краснодаре — один из самых значимых православных храмов Юга России и визитная карточка кубанской столицы.\nСобор был построен в русско-византийском архитектурном стиле, сложившемся в России в первой трети XIX века. План храма представлял собой симметричный равноконечный крест. Две восточные угловые главы были световыми, западная пара — декоративными, выполнявшими роль колоколен. Каждая глава состояла из четырёхгранного барабана и вызолоченного шлемовидного купола. \nПри соборе действует воскресная школа для детей и взрослых, где изучаются основы православной веры, история церкви и казачества. \nВойсковой собор Александра Невского в Краснодаре — важнейший культурно-исторический памятник, хранящий память о казачьем прошлом Кубани.\";s:7:\"h1_font\";a:15:{s:4:\"size\";a:1:{s:7:\"desktop\";i:32;}s:10:\"lineHeight\";a:1:{s:7:\"desktop\";d:1.5;}s:6:\"family\";s:7:\"inherit\";s:6:\"google\";b:0;s:6:\"weight\";s:3:\"700\";s:7:\"variant\";s:3:\"700\";s:5:\"color\";s:8:\"palette3\";s:8:\"sizeType\";s:2:\"px\";s:8:\"lineType\";s:1:\"-\";s:13:\"letterSpacing\";a:1:{s:7:\"desktop\";s:0:\"\";}s:11:\"spacingType\";s:2:\"em\";s:5:\"style\";s:6:\"normal\";s:9:\"transform\";s:0:\"\";s:8:\"fallback\";s:0:\"\";s:4:\"flag\";b:1;}s:7:\"h2_font\";a:15:{s:4:\"size\";a:1:{s:7:\"desktop\";i:28;}s:10:\"lineHeight\";a:1:{s:7:\"desktop\";d:1.5;}s:6:\"family\";s:7:\"inherit\";s:6:\"google\";b:0;s:6:\"weight\";s:3:\"700\";s:7:\"variant\";s:3:\"700\";s:5:\"color\";s:8:\"palette3\";s:8:\"sizeType\";s:2:\"px\";s:8:\"lineType\";s:1:\"-\";s:13:\"letterSpacing\";a:1:{s:7:\"desktop\";s:0:\"\";}s:11:\"spacingType\";s:2:\"em\";s:5:\"style\";s:6:\"normal\";s:9:\"transform\";s:0:\"\";s:8:\"fallback\";s:0:\"\";s:4:\"flag\";b:1;}s:7:\"h3_font\";a:15:{s:4:\"size\";a:1:{s:7:\"desktop\";i:24;}s:10:\"lineHeight\";a:1:{s:7:\"desktop\";d:1.5;}s:6:\"family\";s:7:\"inherit\";s:6:\"google\";b:0;s:6:\"weight\";s:3:\"700\";s:7:\"variant\";s:3:\"700\";s:5:\"color\";s:8:\"palette3\";s:8:\"sizeType\";s:2:\"px\";s:8:\"lineType\";s:1:\"-\";s:13:\"letterSpacing\";a:1:{s:7:\"desktop\";s:0:\"\";}s:11:\"spacingType\";s:2:\"em\";s:5:\"style\";s:6:\"normal\";s:9:\"transform\";s:0:\"\";s:8:\"fallback\";s:0:\"\";s:4:\"flag\";b:0;}s:7:\"h4_font\";a:15:{s:4:\"size\";a:1:{s:7:\"desktop\";i:22;}s:10:\"lineHeight\";a:1:{s:7:\"desktop\";d:1.5;}s:6:\"family\";s:7:\"inherit\";s:6:\"google\";b:0;s:6:\"weight\";s:3:\"700\";s:7:\"variant\";s:3:\"700\";s:5:\"color\";s:8:\"palette4\";s:8:\"sizeType\";s:2:\"px\";s:8:\"lineType\