hadow-card);\n    transition: var(--transition);\n    border-bottom: 3px solid transparent;\n    display: flex;\n    flex-direction: column;\n    align-items: center;\n}\n\n.service-card:hover {\n    transform: translateY(-8px);\n    box-shadow: var(--shadow-hover);\n    border-bottom-color: var(--color-accent);\n}\n\n.service-icon {\n    width: 70px;\n    height: 70px;\n    background: linear-gradient(135deg, var(--color-accent), var(--color-accent-hover));\n    border-radius: 50%;\n    display: flex;\n    align-items: center;\n    justify-content: center;\n    margin-bottom: 20px;\n    font-size: 28px;\n    color: var(--color-primary);\n}\n\n.service-card h3 {\n    font-size: 20px;\n    margin-bottom: 12px;\n}\n\n.service-card p {\n    color: var(--color-text-light);\n    margin-bottom: 20px;\n    flex-grow: 1;\n}\n\n.service-link {\n    color: var(--color-secondary);\n    font-weight: 500;\n    display: inline-flex;\n    align-items: center;\n    gap: 5px;\n}\n.service-link:hover { gap: 10px; }\n\n/* ===== БЛОК НОВОСТЕЙ ===== */\n.news-section {\n    padding: 80px 0;\n    background: var(--color-bg);\n}\n\n.news-grid {\n    display: grid;\n    grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));\n    gap: 30px;\n}\n\n.news-card {\n    background: white;\n    border-radius: var(--radius);\n    overflow: hidden;\n    box-shadow: var(--shadow-card);\n    transition: var(--transition);\n}\n.news-card:hover {\n    transform: translateY(-5px);\n    box-shadow: var(--shadow-hover);\n}\n\n.news-image {\n    height: 200px;\n    background: #ddd;\n    background-size: cover;\n    background-position: center;\n}\n\n.news-content {\n    padding: 25px;\n}\n\n.news-date {\n    display: inline-block;\n    padding: 5px 15px;\n    background: var(--color-accent);\n    color: var(--color-primary);\n    border-radius: 20px;\n    font-size: 13px;\n    font-weight: 600;\n    margin-bottom: 12px;\n}\n\n.news-card h3 {\n    font-size: 18px;\n    margin-bottom: 10px;\n}\n\n.news-excerpt {\n    color: var(--color-text-light);\n    font-size: 14px;\n    margin-bottom: 15px;\n}\n\n.news-read-more {\n    color: var(--color-secondary);\n    font-weight: 500;\n    font-size: 14px;\n}\n\n/* ===== РАСПИСАНИЕ ===== */\n.schedule-section {\n    padding: 60px 0;\n}\n\n.schedule-table {\n    background: white;\n    border-radius: var(--radius);\n    box-shadow: var(--shadow-card);\n    overflow: hidden;\n}\n\n.schedule-row {\n    display: grid;\n    grid-template-columns: 1fr 2fr 1fr;\n    padding: 20px 25px;\n    border-bottom: 1px solid #eee;\n    align-items: center;\n    transition: var(--transition);\n}\n.schedule-row:last-child { border-bottom: none; }\n.schedule-row:hover { background: var(--color-bg); }\n\n.schedule-day { font-weight: 600; color: var(--color-primary); }\n.schedule-service { color: var(--color-text); }\n.schedule-time {\n    background: var(--color-accent);\n    color: var(--color-primary);\n    padding: 5px 15px;\n    border-radius: 20px;\n    font-weight: 600;\n    font-size: 14px;\n    text-align: center;\n}\n\n/* ===== ПОДВАЛ ===== */\n.site-footer {\n    background: var(--color-primary);\n    color: white;\n    padding: 60px 0 30px;\n}\n\n.footer-grid {\n    display: grid;\n    grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));\n    gap: 40px;\n    margin-bottom: 40px;\n}\n\n.footer-widget h4 {\n    color: var(--color-accent);\n    margin-bottom: 20px;\n    font-size: 18px;\n}\n\n.footer-widget ul { list-style: none; }\n.footer-widget ul li { margin-bottom: 10px; }\n.footer-widget ul li a {\n    color: rgba(255,255,255,0.8);\n    transition: var(--transition);\n}\n.footer-widget ul li a:hover {\n    color: var(--color-accent);\n    padding-left: 5px;\n}\n\n.footer-bottom {\n    text-align: center;\n    padding-top: 25px;\n    border-top: 1px solid rgba(201, 169, 97, 0.3);\n    color: rgba(255,255,255,0.6);\n    font-size: 14px;\n}\n\n/* ===== АДАПТИВНОСТЬ ===== */\n@media (max-width: 992px) {\n    .main-navigation ul {\n        flex-wrap: wrap;\n        justify-content: center;\n    }\n    .hero-title { font-size: 36px; }\n}\n\n@media (max-width: 768px) {\n    .header-inner { flex-wrap: wrap; }\n    \n    .main-navigation {\n        order: 3;\n        width: 100%;\n        margin-top: 15px;\n    }\n    \n    .main-navigation ul {\n        flex-direction: column;\n        align-items: center;\n    }\n    \n    .main-navigation ul ul {\n        position: static;\n        opacity: 1;\n        visibility: visible;\n        transform: none;\n        box-shadow: none;\n        border-top: none;\n        border-left: 3px solid var(--color-accent);\n        margin-left: 15px;\n        margin-top: 5px;\n        padding-left: 10px;\n    }\n    \n    .hero-title { font-size: 28px; }\n    .hero-subtitle { font-size: 18px; }\n    \n    .schedule-row {\n        grid-template-columns: 1fr;\n        gap: 10px;\n        text-align: center;\n    }\n}','church-kadence-child','','inherit','closed','closed','','26-revision-v1','','','2026-03-08 12:24:50','2026-03-08 09:24:50','',26,'http://danil.local/?p=29',0,'revision','',0),(30,1,'2026-03-08 13:10:37','2026-03-08 10:10:37','','ukY7RJWKF6iBluOGj2Jg','','inherit','open','closed','','uky7rjwkf6ibluogj2jg','','','2026-03-08 13:10:37','2026-03-08 10:10:37','',0,'http://danil.local/wp-content/uploads/2026/03/ukY7RJWKF6iBluOGj2Jg.webp',0,'attachment','image/webp',0),(35,1,'2026-03-08 14:03:24','2026-03-08 11:03:24','<!-- wp:kadence/rowlayout {\"uniqueID\":\"23_feed71-9e\",\"columns\":1,\"colLayout\":\"equal\",\"firstColumnWidth\":0,\"secondColumnWidth\":0,\"thirdColumnWidth\":0,\"fourthColumnWidth\":0,\"fifthColumnWidth\":0,\"sixthColumnWidth\":0,\"kbVersion\":2} -->\n<!-- wp:kadence/column {\"borderWidth\":[\"\",\"\",\"\",\"\"],\"uniqueID\":\"23_b74723-33\",\"kbVersion\":2} -->\n<div class=\"wp-block-kadence-column kadence-column23_b74723-33\"><div class=\"kt-inside-inner-col\"></div></div>\n<!-- /wp:kadence/column -->\n<!-- /wp:kadence/rowlayout 