borderRadius\":[10,10,10,10],\"showCaption\":false,\"globalAlt\":true,\"imagePosition\":\"50% 50%\"} -->\n<figure class=\"wp-block-kadence-image kb-image55_5331a6-8e kb-image-is-ratio-size\"><div class=\"kb-is-ratio-image kb-image-ratio-land32\"><img src=\"http://danil.local/wp-content/uploads/2026/03/a-diverse-choir-performs-indoors-under-soft.jpeg\" alt=\"\" class=\"kb-img wp-image-62\"/></div></figure>\n<!-- /wp:kadence/image -->\n\n<!-- wp:kadence/image {\"id\":63,\"ratio\":\"square\",\"useRatio\":true,\"linkDestination\":\"none\",\"uniqueID\":\"55_e73a6f-05\",\"marginDesktop\":[0,\"\",0,\"\"],\"borderRadius\":[10,10,10,10],\"showCaption\":false} -->\n<figure class=\"wp-block-kadence-image kb-image55_e73a6f-05 kb-image-is-ratio-size\"><div class=\"kb-is-ratio-image kb-image-ratio-square\"><img src=\"http://danil.local/wp-content/uploads/2026/03/Example-B-Roll-Image-4-scaled-1.jpg\" alt=\"\" class=\"kb-img wp-image-63\"/></div></figure>\n<!-- /wp:kadence/image --></div></div>\n<!-- /wp:kadence/column -->\n<!-- /wp:kadence/rowlayout --></div></div>\n<!-- /wp:kadence/column -->\n<!-- /wp:kadence/rowlayout --></div></div>\n<!-- /wp:kadence/column -->\n<!-- /wp:kadence/rowlayout -->','Новости','','inherit','closed','closed','','55-revision-v1','','','2026-03-08 14:12:24','2026-03-08 11:12:24','',55,'http://danil.local/?p=65',0,'revision','',0),(66,1,'2026-03-08 14:13:34','2026-03-08 11:13:34','<div class=\"donate-page-wrapper\">\n\n  <div class=\"donate-hero\">\n    <div class=\"donate-hero-icon\">&#10013;</div>\n    <h1>Пожертвование</h1>\n    <p>Помогите сохранить духовную красоту нашего храма</p>\n  </div>\n\n  <div class=\"donate-appeal\">\n    <p>Дорогие братья и сестры!</p>\n    <p>С любовью и благодарностью обращаемся к вам от имени Войскового собора святого благоверного князя Александра Невского в городе Краснодаре.</p>\n    <p>Наш храм нуждается в вашей поддержке для осуществления важнейшего дела — <strong>росписи собора</strong>. Каждый ваш вклад — это частичка любви и заботы о духовном доме, где мы молимся и находим утешение.</p>\n  </div>\n\n  <div class=\"donate-methods\">\n    <h2>Как поддержать храм</h2>\n    <div class=\"donate-methods-grid\">\n      <div class=\"donate-method-card\">\n        <div class=\"donate-method-icon\">&#128179;</div>\n        <h3>Банковской картой</h3>\n        <p>Онлайн-перевод на реквизиты храма</p>\n      </div>\n      <div class=\"donate-method-card\">\n        <div class=\"donate-method-icon\">&#128241;</div>\n        <h3>СБП</h3>\n        <p>Система быстрых платежей через мобильный банк</p>\n      </div>\n      <div class=\"donate-method-card\">\n        <div class=\"donate-method-icon\">&#9962;</div>\n        <h3>В храме</h3>\n        <p>Лично в киоске собора (07:00–19:00)</p>\n      </div>\n      <div class=\"donate-method-card\">\n        <div class=\"donate-method-icon\">&#127970;</div>\n        <h3>Банковский перевод</h3>\n        <p>По реквизитам организации</p>\n      </div>\n    </div>\n  </div>\n\n  <div class=\"donate-contacts\">\n    <h2>Связаться с нами</h2>\n    <div class=\"donate-contacts-table\">\n      <div class=\"donate-contact-row\">\n        <div class=\"donate-contact-label\">&#128222; Телефон</div>\n        <div class=\"donate-contact-value\"><a href=\"tel:+78612620020\">(861) 262-00-20</a></div>\n      </div>\n      <div class=\"donate-contact-row\">\n        <div class=\"donate-contact-label\">&#128222; Киоск (07:00–19:00)</div>\n        <div class=\"donate-contact-value\"><a href=\"tel:+79530807672\">8-953-080-76-72</a></div>\n      </div>\n      <div class=\"donate-contact-row\">\n        <div class=\"donate-contact-label\">&#9993; Email</div>\n        <div class=\"donate-contact-value\"><a href=\"mailto:nevskiy-sobor@mail.ru\">nevskiy-sobor@mail.ru</a></div>\n      </div>\n    </div>\n  </div>\n\n  <div class=\"donate-treby\">\n    <h2>Требы и поминовения</h2>\n    <p class=\"donate-treby-intro\">Вы можете заказать требы и поминовения, обратившись в киоск собора или по телефону.</p>\n    <div class=\"donate-treby-grid\">\n      <div class=\"donate-treby-card\">\n        <h3>Панихида</h3>\n        <div class=\"donate-treby-price\">50 &#8381;</div>\n        <p>за 10 имён</p>\n      </div>\n      <div class=\"donate-treby-card\">\n        <h3>Молебен водосвятный</h3>\n        <div class=\"donate-treby-price\">100 &#8381;</div>\n        <p>за 10 имён</p>\n      </div>\n      <div class=\"donate-treby-card\">\n        <h3>Молебен с акафистом</h3>\n        <div class=\"donate-treby-price\">100 &#8381;</div>\n        <p>за 10 имён</p>\n      </div>\n      <div class=\"donate-treby-card\">\n        <h3>Молебен общий</h3>\n        <div class=\"donate-treby-price\">100 &#8381;</div>\n        <p>за 10 имён</p>\n      </div>\n      <div class=\"donate-treby-card\">\n        <h3>Обедня</h3>\n        <div class=\"donate-treby-price\">50 &#8381;</div>\n        <p>за 10 имён</p>\n      </div>\n      <div class=\"donate-treby-card\">\n        <h3>Сугубая ектения</h3>\n        <div class=\"donate-treby-price\">50 &#8381;</div>\n        <p>за 1 имя</p>\n      </div>\n      <div class=\"donate-treby-card\">\n        <h3>Сорокоуст (устное)</h3>\n        <div class=\"donate-treby-price\">80 &#8381;</div>\n        <p>за 1 имя</p>\n      </div>\n      <div class=\"donate-treby-card\">\n        <h3>Сорокоуст (с частицей)</h3>\n        <div class=\"donate-treby-price\">160 &#8381;</div>\n        <p>за 1 имя</p>\n      </div>\n      <div class=\"donate-treby-card\">\n        <h3>Полугодовое поминовение</h3>\n        <div class=\"donate-treby-price\">500 &#8381;</div>\n        <p>за 1 имя</p>\n      </div>\n      <div class=\"donate-treby-card\">\n        <h3>Годовое поминовение</h3>\n        <div class=\"donate-treby-price\">1000 &#8381;</div>\n        <p>за 1 имя</p>\n      </div>\n    </div>\n  </div>\n\n  <div class=\"donate-footer-text\">\n    <p>&#128591; Ваша помощь делает возможным продолжение росписи храма и сохранение его духовной красоты для будущих поколений.</p>\n    <p><strong>С любовью и благодарностью,<br>Приход Войскового собора</strong></p>\n  </div>\n\n</div>','Пожертвовать','','publish','closed','closed','','donate','','','2026-03-08 14:13:34','2026-03-08 11:13:34','',0,'http://danil.local/?page_id=66',0,'page','',0),(67,1,'2026-03-08 14:12:57','2026-03-08 11:12:57','','Photo by Yuri Semenyaga','','inherit','open','closed','','photo-by-yuri-semenyaga','','','2026-03-08 14:12:57','2026-03-08 11:12:57','',0,'http://danil.local/wp-content/uploads/2026/03/young-choir-boys-singing-during-a-church.jpeg',0,'attachment','image/jpeg',0),(68,1,'2026-03-08 14:12:57','2026-03-08 11:12:57','','Photo by David Iloba','','inherit','open','closed','','photo-by-david-iloba','','','2026-03-08 14:12:57','2026-03-08 11:12:57','',0,'http://danil.local/wp-content/uploads/2026/03/a-vibrant-choir-in-golden-gowns-sings.jpeg',0,'attachment','image/jpeg',0),(69,1,'2026-03-08 14:12:57','2026-03-08 11:12:57','','Photo by Pavel Danilyuk','','inherit','open','closed','','photo-by-pavel-danilyuk-6','','','2026-03-08 14:12:57','2026-03-08 11:12:57','',0,'http://danil.local/wp-content/uploads/2026/03/a-choir-in-red-robes-performs-during.jpeg',0,'attachment','image/jpeg',0),(70,1,'2026-03-08 14:12:58','2026-03-08 11:12:58','','Photo by Pavel Danilyuk','','inherit','open','closed','','photo-by-pavel-danilyuk-7','','','2026-03-08 14:12:58','2026-03-08 11:12:58','',0,'http://danil.local/wp-content/uploads/2026/03/pastor-leading-a-church-service-with-choir.jpeg',0,'attachment','image/jpeg',0),(71,1,'2026-03-08 14:13:02','2026-03-08 11:13:02','<!-- wp:kadence/rowlayout {\"uniqueID\":\"66_61912e-7f\",\"columns\":1,\"colLayout\":\"equal\",\"maxWidth\":800,\"bgColor\":\"palette3\",\"align\":\"full\",\"firstColumnWidth\":0,\"secondColumnWidth\":0,\"thirdColumnWidth\":0,\"fourthColumnWidth\":0,\"fifthColumnWidth\":0,\"sixthColumnWidth\":0,\"bgColorClass\":\"theme-palette3\",\"padding\":[\"xxl\",\"\",\"xxl\",\"\"],\"kbVersion\":